// math.ts
export function add(a: number, b: number): number {
  return a + b;
}

export interface MathResult {
  value: number;
  operation: string;
}

export type Operator = '+' | '-' | '*' | '/';

// app.ts
import { add } from './math';           // импорт значения
import type { MathResult } from './math'; // импорт типа
import { type Operator } from './math';   // инлайн-форма (TS 4.5+)

const result: MathResult = {
  value: add(2, 3),
  operation: '+'
};

// app.js (после компиляции)
import { add } from './math';
// import type — полностью удалён!
// import { type Operator } — тоже удалён!

const result = {
  value: add(2, 3),
  operation: '+'
};

